import fs from 'fs'; const settingsFile = './data/autoread_settings.json'; function initSettings() { const dir = './data'; if (!fs.existsSync(dir)) { fs.mkdirSync(dir, { recursive: true }); } if (!fs.existsSync(settingsFile)) { const initialSettings = { enabled: false, mode: 'both', delay: 2000, whitelist: [], blacklist: [], silent: true }; fs.writeFileSync(settingsFile, JSON.stringify(initialSettings, null, 2)); } } initSettings(); function loadSettings() { try { const data = fs.readFileSync(settingsFile, 'utf8'); return JSON.parse(data); } catch (error) { return { enabled: false, mode: 'both', delay: 2000, whitelist: [], blacklist: [], silent: true }; } } function saveSettings(settings) { try { fs.writeFileSync(settingsFile, JSON.stringify(settings, null, 2)); } catch (error) { console.error('🦊 Error saving autoread settings:', error); } } function cleanJid(jid) { if (!jid) return jid; const clean = jid.split(':')[0]; return clean.includes('@') ? clean : clean + '@s.whatsapp.net'; } let autoreadActive = false; function setupAutoread(sock) { if (autoreadActive) return; sock.ev.on('messages.upsert', async ({ messages }) => { try { const settings = loadSettings(); if (!settings.enabled || settings.mode === 'off') return; for (const message of messages) { if (message.key.fromMe) continue; const chatJid = cleanJid(message.key.remoteJid); const isGroup = chatJid.endsWith('@g.us'); const messageId = message.key.id; if (settings.whitelist.includes(chatJid)) continue; const forceRead = settings.blacklist.includes(chatJid); let shouldRead = false; if (forceRead) { shouldRead = true; } else if (settings.mode === 'both') { shouldRead = true; } else if (settings.mode === 'groups' && isGroup) { shouldRead = true; } else if (settings.mode === 'dms' && !isGroup) { shouldRead = true; } if (shouldRead) { setTimeout(async () => { try { await sock.readMessages([{ remoteJid: chatJid, id: messageId }]); } catch (e) {} }, settings.delay); } } } catch (error) {} }); autoreadActive = true; } export default { name: 'autoread', alias: ['autoview', 'autoseen', 'read', 'foxyread'], category: 'utility', ownerOnly: true, async execute(sock, m, args, PREFIX, extra) { const chatId = m.key.remoteJid; const { jidManager } = extra; const sendMessage = async (text) => { return await sock.sendMessage(chatId, { text }, { quoted: m }); }; if (!jidManager.isOwner(m)) { return await sock.sendMessage(chatId, { react: { text: "👑", key: m.key } }); } const settings = loadSettings(); const subCommand = args[0]?.toLowerCase(); if (!autoreadActive) { setupAutoread(sock); } if (!subCommand || subCommand === 'status') { const modeText = settings.mode === 'groups' ? '👥 Groups Only' : settings.mode === 'dms' ? '💬 DMs Only' : settings.mode === 'both' ? '🌍 All' : '❌ Off'; return await sendMessage( `┌─⧭ *FOXY AUTO READ* 📖 ⧭─┐ │ ├─⧭ *Status:* ${settings.enabled ? '✅ ON' : '❌ OFF'} ├─⧭ *Mode:* ${modeText} ├─⧭ *Delay:* ${settings.delay}ms ├─⧭ *Excluded:* ${settings.whitelist.length} ├─⧭ *Forced:* ${settings.blacklist.length} │ ├─⧭ *Commands:* │ • ${PREFIX}autoread groups │ • ${PREFIX}autoread dms │ • ${PREFIX}autoread both │ • ${PREFIX}autoread off │ • ${PREFIX}autoread delay 2000 │ • ${PREFIX}autoread help │ └─⧭🦊` ); } if (subCommand === 'groups') { settings.enabled = true; settings.mode = 'groups'; saveSettings(settings); return await sendMessage( `┌─⧭ *✅ GROUPS ONLY* ⧭─┐ │ ├─⧭ Only group messages will be read │ └─⧭🦊` ); } if (subCommand === 'dms') { settings.enabled = true; settings.mode = 'dms'; saveSettings(settings); return await sendMessage( `┌─⧭ *✅ DMS ONLY* ⧭─┐ │ ├─⧭ Only direct messages will be read │ └─⧭🦊` ); } if (subCommand === 'both') { settings.enabled = true; settings.mode = 'both'; saveSettings(settings); return await sendMessage( `┌─⧭ *✅ ALL MESSAGES* ⧭─┐ │ ├─⧭ All messages will be read │ └─⧭🦊` ); } if (subCommand === 'off') { settings.enabled = false; settings.mode = 'off'; saveSettings(settings); return await sendMessage( `┌─⧭ *❌ AUTO READ OFF* ⧭─┐ │ ├─⧭ Messages will not be auto-read │ └─⧭🦊` ); } if (subCommand === 'delay') { const delay = parseInt(args[1]); if (isNaN(delay) || delay < 0 || delay > 60000) { return await sendMessage( `┌─⧭ *⚠️ INVALID DELAY* ⧭─┐ │ ├─⧭ Use: 0 - 60000 ms ├─⧭ Example: ${PREFIX}autoread delay 3000 │ └─⧭🦊` ); } settings.delay = delay; saveSettings(settings); return await sendMessage( `┌─⧭ *✅ DELAY SET* ⧭─┐ │ ├─⧭ ${delay}ms (${delay/1000}s) │ └─⧭🦊` ); } if (subCommand === 'help') { return await sendMessage( `┌─⧭ *📖 AUTO READ HELP* ⧭─┐ │ ├─⧭ *Commands:* │ • ${PREFIX}autoread groups │ • ${PREFIX}autoread dms │ • ${PREFIX}autoread both │ • ${PREFIX}autoread off │ • ${PREFIX}autoread delay <ms> │ • ${PREFIX}autoread status │ • ${PREFIX}autoread help │ ├─⧭ *Modes:* │ • groups - Only groups │ • dms - Only direct messages │ • both - All messages │ • off - Disable │ └─⧭🦊` ); } await sendMessage( `┌─⧭ *❓ INVALID COMMAND* ⧭─┐ │ ├─⧭ Use ${PREFIX}autoread help │ └─⧭🦊` ); } }; export function startAutoread(sock) { if (!autoreadActive) { setupAutoread(sock); } }